    33→function FlashCountdown({ endTime }: { endTime?: string }) {
    34→  const getRemaining = () => {
    35→    if (!endTime) return { h: 5, m: 59, s: 59 };
    36→    const diff = Math.max(0, new Date(endTime).getTime() - Date.now());
    37→    const totalSecs = Math.floor(diff / 1000);
    38→    return {
    39→      h: Math.floor(totalSecs / 3600),
    40→      m: Math.floor((totalSecs % 3600) / 60),
    41→      s: totalSecs % 60,
    42→    };
    43→  };
    44→  const [time, setTime] = useState(getRemaining);
    45→  useEffect(() => {
    46→    const iv = setInterval(() => setTime(getRemaining()), 1000);
    47→    return () => clearInterval(iv);
    48→  }, [endTime]);
    49→  const pad = (n: number) => String(n).padStart(2, "0");
    50→  return (
    51→    <div className="flex items-center gap-1" dir="ltr">
    52→      {[pad(time.h), pad(time.m), pad(time.s)].map((v, i) => (
    53→        <span key={i} className="flex items-center gap-1">
    54→          <span className="bg-[#6B3F2A] text-white font-bold text-lg w-10 h-10 flex items-center justify-center rounded-lg tabular-nums">
    55→            {v}
    56→          </span>
    57→          {i < 2 && <span className="text-[#6B3F2A] font-bold text-lg">:</span>}
    58→        </span>
    59→      ))}
    60→    </div>
    61→  );
    62→}
