   935→function StatsSection({ isRtl, t }: { isRtl: boolean; t: (k: string) => string }) {
   936→  const { data: items } = useQuery<any[]>({
   937→    queryKey: ["/api/stats"],
   938→    staleTime: 5 * 60_000,
   939→  });
   940→
   941→  const fallback = [
   942→    { valueAr: "+٥٠٠", valueEn: "500+", labelAr: t('happyCustomers'), labelEn: t('happyCustomers'), color: "#E8637A" },
   943→    { valueAr: "+١٥٠", valueEn: "150+", labelAr: t('luxuryFragrances'), labelEn: t('luxuryFragrances'), color: "#E8637A" },
   944→    { valueAr: "٩٩٪", valueEn: "99%", labelAr: t('customerSatisfaction'), labelEn: t('customerSatisfaction'), color: "#E8637A" },
   945→    { valueAr: "٢-٤", valueEn: "2-4", labelAr: t('deliveryDays'), labelEn: t('deliveryDays'), color: "#E8637A" },
   946→  ];
   947→
   948→  const list = (items && items.length > 0) ? items : fallback;
   949→  if (list.length === 0) return null;
   950→
   951→  const cols = list.length === 1 ? "grid-cols-1"
   952→    : list.length === 2 ? "grid-cols-2"
   953→    : list.length === 3 ? "grid-cols-1 sm:grid-cols-3"
   954→    : list.length === 4 ? "grid-cols-2 md:grid-cols-4"
