   974→              >
   975→                {isRtl ? (stat.valueAr || stat.valueEn) : (stat.valueEn || stat.valueAr)}
   976→              </span>
   977→              <span className="text-xs font-bold uppercase tracking-wider text-gray-700 mt-2">
