function FloatingBean({ delay, x, size, duration, opacity }: {
  delay: number; x: number; size: number; duration: number; opacity: number;
}) {
  return (
    <motion.div
      className="absolute pointer-events-none select-none"
      style={{ left: `${x}%`, bottom: "-60px", width: size, height: size * 0.7, opacity }}
      animate={{ y: [0, -window.innerHeight - 100], rotate: [0, 360], x: [0, (Math.random() - 0.5) * 80] }}
      transition={{ duration, delay, repeat: Infinity, ease: "linear" }}
